from __future__ import annotations

import base64
import io
import runpy
import shutil
import sys
import tempfile
import zipfile
from pathlib import Path

BUNDLE_B64 = """"""
BUNDLE_SHA = "ea76a6793bd73a1b1e5b57f3db1c45465c3b6e82830d72d7dd8f06cc91b2dd5d"
BUNDLE_DIR = Path(tempfile.gettempdir()) / "review_intelligence_render_bundle"


def extract_bundle() -> Path:
    backend_server = BUNDLE_DIR / "backend" / "server.py"
    marker = BUNDLE_DIR / ".bundle_sha"
    if backend_server.exists() and marker.exists() and marker.read_text(encoding="utf-8") == BUNDLE_SHA:
        return BUNDLE_DIR
    if BUNDLE_DIR.exists():
        shutil.rmtree(BUNDLE_DIR)
    BUNDLE_DIR.mkdir(parents=True, exist_ok=True)
    raw = base64.b64decode(BUNDLE_B64)
    with zipfile.ZipFile(io.BytesIO(raw)) as archive:
        archive.extractall(BUNDLE_DIR)
    marker.write_text(BUNDLE_SHA, encoding="utf-8")
    if not backend_server.exists():
        extracted = sorted(str(path.relative_to(BUNDLE_DIR)) for path in BUNDLE_DIR.rglob("*") if path.is_file())[:30]
        raise FileNotFoundError(f"Bundled backend/server.py was not extracted. First files: {extracted}")
    return BUNDLE_DIR


def main() -> None:
    project_root = extract_bundle()
    backend = project_root / "backend"
    sys.path.insert(0, str(backend))
    sys.path.insert(0, str(project_root))
    runpy.run_path(str(backend / "server.py"), run_name="__main__")


if __name__ == "__main__":
    main()
